def describe_call(*args, **kwargs):
    sorted_kwargs = dict(sorted(kwargs.items()))
    return {
        "count": len(args) + len(kwargs),
        "args": args,
        "kwargs": sorted_kwargs,
    }

tests.content:
from solution import describe_call


def test_no_arguments():
    assert describe_call() == {"count": 0, "args": (), "kwargs": {}}


def test_positional_only():
    result = describe_call(1, 2, 3)
    assert result["args"] == (1, 2, 3)
    assert result["kwargs"] == {}
    assert result["count"] == 3


def test_keyword_only():
    result = describe_call(a=1, b=2)
    assert result["args"] == ()
    assert result["kwargs"] == {"a": 1, "b": 2}
    assert result["count"] == 2


def test_mixed():
    result = describe_call(10, 20, x="hi", y="bye")
    assert result["args"] == (10, 20)
    assert result["kwargs"] == {"x": "hi", "y": "bye"}
    assert result["count"] == 4


def test_args_is_a_tuple_not_a_list():
    # *args is always a tuple; a wrong solution often returns a list.
    assert isinstance(describe_call(1, 2)["args"], tuple), "args must be a tuple"


def test_kwargs_sorted_by_key():
    # The dict must be ordered by key regardless of call order.
    result = describe_call(zeta=1, alpha=2, mid=3)
    assert list(result["kwargs"].keys()) == ["alpha", "mid", "zeta"]

