exercises.solution_code:
def call_each(func, calls):
    results = []
    for args, kwargs in calls:
        results.append(func(*args, **kwargs))
    return results

tests.content:
from solution import call_each


def test_positional_forwarding():
    def add(a, b):
        return a + b

    result = call_each(add, [((1, 2), {}), ((10, 20), {})])
    assert result == [3, 30]


def test_keyword_forwarding():
    def greet(name, *, loud=False):
        return name.upper() if loud else name

    result = call_each(greet, [(("ada",), {}), (("ada",), {"loud": True})])
    assert result == ["ada", "ADA"]


def test_mixed_args_and_kwargs():
    def make(a, b, sep="-"):
        return f"{a}{sep}{b}"

    result = call_each(make, [((1, 2), {}), ((1, 2), {"sep": "+"})])
    assert result == ["1-2", "1+2"]


def test_empty_call_list():
    def f():
        return 1

    assert call_each(f, []) == []


def test_does_not_pass_the_tuple_as_a_single_arg():
    # A common mistake: calling func(args, kwargs) instead of func(*args, **kwargs).
    def takes_three(a, b, c):
        return a + b + c

    assert call_each(takes_three, [((1, 2, 3), {})]) == [6]


def test_preserves_call_order():
    def identity(x):
        return x

    result = call_each(identity, [((i,), {}) for i in [5, 1, 9, 2]])
    assert result == [5, 1, 9, 2]

exercises.solution_code:
import functools


def record_calls(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        wrapper.calls.append((args, kwargs))
        return func(*args, **kwargs)

    wrapper.calls = []
    return wrapper

tests.content:
from solution import record_calls


def test_calls_starts_empty():
    @record_calls
    def f():
        return 1

    assert f.calls == []


def test_records_args_and_kwargs():
    @record_calls
    def add(a, b, *, c=0):
        return a + b + c

    add(1, 2)
    add(3, 4, c=5)
    assert add.calls == [((1, 2), {}), ((3, 4), {"c": 5})]


def test_returns_underlying_result():
    @record_calls
    def mul(a, b):
        return a * b

    assert mul(3, 4) == 12


def test_forwards_arbitrary_signature():
    # The decorator must work on any signature without knowing it in advance.
    @record_calls
    def variadic(*args, **kwargs):
        return (args, kwargs)

    assert variadic(1, 2, x=3) == ((1, 2), {"x": 3})
    assert variadic.calls == [((1, 2), {"x": 3})]


def test_preserves_metadata():
    @record_calls
    def documented(a):
        """Doc string."""
        return a

    assert documented.__name__ == "documented", "use functools.wraps"
    assert documented.__doc__ == "Doc string."


def test_two_decorated_functions_record_independently():
    @record_calls
    def a(x):
        return x

    @record_calls
    def b(x):
        return x

    a(1)
    b(2)
    b(3)
    assert a.calls == [((1,), {})]
    assert b.calls == [((2,), {}), ((3,), {})]

exercises.solution_code:
import functools


def with_defaults(func, **preset):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        # Preset keywords first, then let the caller's kwargs override them.
        merged = {**preset, **kwargs}
        return func(*args, **merged)

    return wrapper

tests.content:
from solution import with_defaults


def make_request(url, *, method="GET", timeout=10):
    return {"url": url, "method": method, "timeout": timeout}


def test_applies_preset_keywords():
    client = with_defaults(make_request, method="POST", timeout=30)
    assert client("/users") == {"url": "/users", "method": "POST", "timeout": 30}


def test_caller_keywords_override_presets():
    client = with_defaults(make_request, method="POST", timeout=30)
    # Call-time kwargs must win over the presets.
    assert client("/x", method="DELETE") == {"url": "/x", "method": "DELETE", "timeout": 30}


def test_positional_args_pass_through():
    def join(a, b, *, sep="-"):
        return f"{a}{sep}{b}"

    j = with_defaults(join, sep="+")
    assert j("left", "right") == "left+right"
    assert j("left", "right", sep="/") == "left/right"


def test_no_presets_behaves_like_plain_call():
    client = with_defaults(make_request)
    assert client("/", method="PUT") == {"url": "/", "method": "PUT", "timeout": 10}


def test_does_not_mutate_preset_between_calls():
    client = with_defaults(make_request, method="POST")
    client("/a", method="PATCH")  # override on one call...
    # ...must not leak into the next call's defaults.
    assert client("/b") == {"url": "/b", "method": "POST", "timeout": 10}


def test_preserves_metadata():
    wrapped = with_defaults(make_request, method="POST")
    assert wrapped.__name__ == "make_request", "use functools.wraps"


def test_override_does_not_duplicate_keyword():
    # The classic bug: passing both preset and caller kwargs unmerged raises
    # "got multiple values for keyword argument". Merging must prevent that.
    client = with_defaults(make_request, timeout=5)
    assert client("/q", timeout=99)["timeout"] == 99
